// // This module decrements its value on each positive edge of the clock signal and resets to the maximum value when the reset input is activated.
module top_module(
    output reg [3:0] out,
    input clk,
    input reset
);always @(posedge clk) begin
        if (reset) begin
            out <= 4'd0;
        end else begin
            out <= out + 1;
        end
    end

endmodule
